 27	void transpose (int N, float complex *A, float complex *Result)
 28	{
 29	  // COnputes C := alpha*op(A)*op(B) + beta*C,
 30	  CBLAS_TRANSPOSE transa = CblasTrans;
 31	  CBLAS_TRANSPOSE transb = CblasNoTrans;
 32	  int rows_opA = N; // number of rows in op(A) and in C
 33	  int col_opB = N; //number of columns of op(B) and in C
 34	  int col_opA = N; //number of columns in op(A) and rows in op(B)
 35	  int col_B; //number of columns in B
 36	  float complex alpha = 1.0+I*0;
 37	  int lda  = rows_opA;
 38	  float complex beta = 0.0+I*0;
 39	  int ldc = rows_opA;
 40	  int i;
 41	  float complex* B;
 42	
 43	  int ldb = col_opB;
 44	
 45	  if (transb == CblasNoTrans) {
 46	    B = (float complex*)calloc(ldb*col_opB,sizeof(float complex));
 47	    col_B= col_opB;
 48	  }
 49	  else {
 50	    B = (float complex*)calloc(ldb*col_opA, sizeof(float complex));
 51	    col_B = col_opA;
 52	  }
 53	  float complex* C = (float complex*)malloc(ldc*col_opB*sizeof(float complex));
 54	
 55	  for (i=0; i<lda*col_B; i+=N+1)
 56	    B[i]=1.0+I*0;
 57	
 58	  cblas_cgemm(CblasRowMajor, transa, transb, rows_opA, col_opB, col_opA, &alpha, A, lda, B, ldb, &beta, C, ldc);
 59	
 60	  memcpy(Result, C, N*N*sizeof(float complex));
 61	
 62	  free(B);
 63	  free(C);
 64	 }
