156	void eigen_vectors_values (int N, float complex *A, float complex *Vectors, float *Values_Matrix)
157	{
158	  // This function computes ORTHONORMAL eigenvectors and eigenvalues of matrix A,
159	  // where Values_Matrix is a diagonal matrix of eigenvalues.
160	  // A=Vectors*Values_Matrix*Vectors'
161	  char jobz = 'V';
162	  char uplo = 'U';
163	  int order_A = N;
164	  int lda = N;
165	  int i;
166	  float* Values = (float*)malloc(sizeof(float)*1*N);
167	
168	  LAPACKE_cheev(LAPACK_ROW_MAJOR, jobz, uplo, order_A, A, lda, Values);
169	
170	  memcpy(Vectors, A, N*N*sizeof(float complex));
171	
172	  for (i=0; i<lda; i+=1)
173	    Values_Matrix[i*(lda+1)]=Values[i];
174	
175	  free(Values);
176	}
