178	 void lin_eq_solver (int N, float complex* A, float complex* B, float complex* Result)
179	{
180	  int n = N;
181	  int lda = N;
182	  int ldb = N;
183	  int nrhs = N;
184	
185	  char transa = 'N';
186	  int* IPIV = malloc(N*N*sizeof(int));
187	
188	  // Compute LU-factorization
189	  LAPACKE_cgetrf(LAPACK_ROW_MAJOR, n, nrhs, A, lda, IPIV);
190	
191	  // Solve AX=B
192	  LAPACKE_cgetrs(LAPACK_ROW_MAJOR, transa, n, nrhs, A, lda, IPIV, B, ldb);
193	
194	  // cgetrs( "N", N, 4, A, lda, IPIV, B, ldb, INFO )
195	
196	  memcpy(Result, B, N*N*sizeof(float complex));
197	
198	  free(IPIV);
199	
200	}

